// Monthly Savings Page
function MonthlySavingsPage() {
  const [monthlyData, setMonthlyData] = useState([]);
  const [members, setMembers] = useState([]);
  const [selectedMember, setSelectedMember] = useState('');
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [savings, setSavings] = useState({});

  const months = [
    { name: 'Baisakh', bs: 1 }, { name: 'Jestha', bs: 2 }, { name: 'Ashadh', bs: 3 },
    { name: 'Shrawan', bs: 4 }, { name: 'Bhadra', bs: 5 }, { name: 'Ashoj', bs: 6 },
    { name: 'Kartik', bs: 7 }, { name: 'Mangsir', bs: 8 }, { name: 'Poush', bs: 9 },
    { name: 'Magh', bs: 10 }, { name: 'Falgun', bs: 11 }, { name: 'Chaitra', bs: 12 }
  ];

  useEffect(() => { fetchMembers(); }, []);

  const fetchMembers = async () => {
    try {
      const response = await api.get('/members');
      const membersData = response.data || response || [];
      setMembers(Array.isArray(membersData) ? membersData : []);
    } catch (error) {
      console.error('Error fetching members:', error);
      setMembers([]);
    }
  };

  const fetchMonthlySavings = async () => {
    if (selectedMember && selectedYear) {
      try {
        const response = await api.get(`/monthly-savings/${selectedMember}/${selectedYear}`);
        const data = response.data || response || [];
        setMonthlyData(Array.isArray(data) ? data : []);
      } catch (error) {
        console.error('Error fetching monthly savings:', error);
        setMonthlyData([]);
      }
    }
  };

  useEffect(() => {
    if (selectedMember && selectedYear) {
      fetchMonthlySavings();
    }
  }, [selectedMember, selectedYear]);

  const getAmount = (month) => {
    const entry = monthlyData.find(m => m.month_bs === month);
    return entry ? entry.amount : savings[month] || '';
  };

  const totalSaved = monthlyData.reduce((sum, m) => sum + parseFloat(m.amount || 0), 0);

  const handleSave = async (month) => {
    const amount = savings[month];
    if (amount && selectedMember) {
      try {
        await api.post('/monthly-savings', {
          member_id: selectedMember,
          year: selectedYear,
          month_bs: month,
          amount: parseFloat(amount)
        });
        alert('Monthly savings saved!');
        fetchMonthlySavings();
        setSavings(prev => ({ ...prev, [month]: undefined }));
      } catch (error) {
        console.error('Error saving:', error);
      }
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this entry?')) {
      try {
        await api.delete(`/monthly-savings/${id}`);
        fetchMonthlySavings();
      } catch (error) {
        console.error('Error deleting:', error);
      }
    }
  };

  return (
    <div className="monthly-savings-page">
      <div className="page-header">
        <h1>Monthly Savings</h1>
        <p>Track monthly savings contributions per member (Bikram Sambat calendar)</p>
      </div>
      <div className="form-section">
        <div className="form-row">
          <select value={selectedMember} onChange={e => { setSelectedMember(e.target.value); setMonthlyData([]); }}>
            <option value="">Select Member</option>
            {members.map(m => <option key={m.id} value={m.id}>{m.member_number} - {m.member_name}</option>)}
          </select>
          <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)}>
            {[...Array(10)].map((_, i) => {
              const year = 2075 + i;
              return <option key={year} value={year}>{year} BS</option>;
            })}
          </select>
        </div>
      </div>
      {selectedMember && (
        <div className="monthly-content">
          <div className="summary-cards">
            <div className="summary-card">
              <h3>Member</h3>
              <div className="summary-value" style={{ fontSize: '1.2rem' }}>
                {members.find(m => m.id == selectedMember)?.member_name || 'Unknown'}
              </div>
            </div>
            <div className="summary-card">
              <h3>Year</h3>
              <div className="summary-value">{selectedYear} BS</div>
            </div>
            <div className="summary-card">
              <h3>Total Saved</h3>
              <div className="summary-value">Rs. {totalSaved.toLocaleString()}</div>
            </div>
            <div className="summary-card">
              <h3>Months Saved</h3>
              <div className="summary-value">{monthlyData.length}/12</div>
            </div>
          </div>
          <div className="monthly-grid">
            <h3>Monthly Contributions</h3>
            <div className="months-container">
              {months.map(month => (
                <div key={month.bs} className="month-card">
                  <div className="month-header">
                    <span className="month-name">{month.name}</span>
                    <span className="month-number">{month.bs}</span>
                  </div>
                  <div className="month-input">
                    <label>Amount (Rs.)</label>
                    <input
                      type="number"
                      value={getAmount(month.bs)}
                      onChange={e => setSavings(prev => ({ ...prev, [month.bs]: e.target.value }))}
                      placeholder="0.00"
                    />
                  </div>
                  <div className="month-actions">
                    <button className="btn-primary" onClick={() => handleSave(month.bs)}>Save</button>
                    {monthlyData.find(m => m.month_bs === month.bs) && (
                      <button className="btn-danger" onClick={() => handleDelete(monthlyData.find(m => m.month_bs === month.bs).id)}>Delete</button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
          {monthlyData.length > 0 && (
            <div className="yearly-overview">
              <h3>Yearly Overview - {selectedYear} BS</h3>
              <div className="yearly-chart">
                {months.map(month => {
                  const entry = monthlyData.find(m => m.month_bs === month.bs);
                  const amount = entry ? parseFloat(entry.amount) : 0;
                  const maxAmount = Math.max(...monthlyData.map(m => parseFloat(m.amount || 0)), 1);
                  const height = Math.max((amount / maxAmount) * 150, 4);
                  return (
                    <div key={month.bs} className="chart-bar-container">
                      <div className="chart-value">{amount > 0 ? `Rs. ${amount.toLocaleString()}` : '-'}</div>
                      <div className="chart-bar" style={{ height: `${height}px` }}></div>
                      <div className="chart-label">{month.name}</div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

