        setEditingId(data.id);
        setFormData({
          full_name: data.full_name || '',
          citizenship_number: data.citizenship_number || '',
          birth_date: data.birth_date || '',
          birth_date_bs: data.birth_date_bs || '',
          nationality: data.nationality || '',
          marital_status: data.marital_status || '',
          spouse_name: data.spouse_name || '',
          issued_date: data.issued_date || '',
          issued_district: data.issued_district || '',
          province: data.province || '',
          district: data.district || '',
          municipality: data.municipality || '',
          ward_number: data.ward_number || '',
          tole: data.tole || '',
          phone: data.phone || '',
          email: data.email || ''
        });
        setExistingPhotos({
          photo: data.photo || '',
          citizenship_front: data.citizenship_front || '',
          citizenship_back: data.citizenship_back || ''
        });
      } else {
        setCitizenshipData(null);
        setEditingId(null);
        resetForm();
      }
    } catch (error) {
      console.error('Error fetching citizenship:', error);
      setCitizenshipData(null);
      setEditingId(null);
      resetForm();
    }
  };

  const resetForm = () => {
    setFormData({
      full_name: '',
      citizenship_number: '',
      birth_date: '',
      birth_date_bs: '',
      nationality: '',
      marital_status: '',
      spouse_name: '',
      issued_date: '',
      issued_district: '',
      province: '',
      district: '',
      municipality: '',
      ward_number: '',
      tole: '',
      phone: '',
      email: ''
    });
    setPhotos({ photo: null, citizenship_front: null, citizenship_back: null });
    setEditingId(null);
  };

  useEffect(() => {
    if (selectedMember) {
      fetchCitizenship(selectedMember);
    }
  }, [selectedMember]);

  const handleFileChange = (e, field) => {
    const file = e.target.files[0];
    if (file) {
      setPhotos(prev => ({ ...prev, [field]: file }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedMember) {
      alert('Please select a member first');
      return;
    }

    setLoading(true);
    const formDataToSend = new FormData();
    formDataToSend.append('member_id', selectedMember);
    
    Object.keys(formData).forEach(key => {
      formDataToSend.append(key, formData[key]);
    });
    
    if (photos.photo) formDataToSend.append('photo', photos.photo);
    if (photos.citizenship_front) formDataToSend.append('citizenship_front', photos.citizenship_front);
    if (photos.citizenship_back) formDataToSend.append('citizenship_back', photos.citizenship_back);
    
    if (existingPhotos.photo) formDataToSend.append('existing_photo', existingPhotos.photo);
    if (existingPhotos.citizenship_front) formDataToSend.append('existing_citizenship_front', existingPhotos.citizenship_front);
    if (existingPhotos.citizenship_back) formDataToSend.append('existing_citizenship_back', existingPhotos.citizenship_back);

    try {
      const token = localStorage.getItem('token');
      const url = editingId 
        ? `${API_BASE}/citizenship/${editingId}`
        : `${API_BASE}/citizenship`;
      const method = editingId ? 'PUT' : 'POST';
      
      const res = await fetch(url, {
        method,
        headers: { 
          'Authorization': `Bearer ${token}`
        },
        body: formDataToSend
      });
      
      const data = await res.json();
      if (data.success) {
        alert(editingId ? 'Citizenship details updated!' : 'Citizenship details saved!');
        fetchCitizenship(selectedMember);
        fetchAllCitizenships();
      } else {
        alert(data.message || 'Error saving citizenship');
      }
    } catch (error) {
      console.error('Error saving citizenship:', error);
      alert('Error saving citizenship');
    }
    setLoading(false);
  };

  const handleDelete = async () => {
    if (!editingId) return;
    if (!window.confirm('Are you sure you want to delete this citizenship details?')) return;

    try {
      await api.delete(`/citizenship/${editingId}`);
      alert('Citizenship details deleted!');
      setCitizenshipData(null);
      setEditingId(null);
      resetForm();
      fetchAllCitizenships();
    } catch (error) {
      console.error('Error deleting citizenship:', error);
      alert('Error deleting citizenship');
    }
  };

  const viewPhoto = () => {
    if (existingPhotos.photo || existingPhotos.citizenship_front || existingPhotos.citizenship_back) {
      setShowModal(true);
    }
  };

  const handleViewFromTable = (doc) => {
    setSelectedDocument(doc);
    setShowDetailsModal(true);
  };

  const handleEditFromTable = (doc) => {
    setSelectedMember(doc.member_id);
    setEditingId(doc.id);
    setCitizenshipData(doc);
    setFormData({
      full_name: doc.full_name || '',
      citizenship_number: doc.citizenship_number || '',
      birth_date: doc.birth_date || '',
      birth_date_bs: doc.birth_date_bs || '',
      nationality: doc.nationality || '',
      marital_status: doc.marital_status || '',
      spouse_name: doc.spouse_name || '',
      issued_date: doc.issued_date || '',
      issued_district: doc.issued_district || '',
      province: doc.province || '',
      district: doc.district || '',
      municipality: doc.municipality || '',
      ward_number: doc.ward_number || '',
      tole: doc.tole || '',
      phone: doc.phone || '',
      email: doc.email || ''
    });
    setExistingPhotos({
      photo: doc.photo || '',
      citizenship_front: doc.citizenship_front || '',
      citizenship_back: doc.citizenship_back || ''
    });
    setViewMode('form');
  };

  const handleDeleteFromTable = async (id) => {
    if (!window.confirm('Are you sure you want to delete this citizenship details?')) return;

    try {
      await api.delete(`/citizenship/${id}`);
      alert('Citizenship details deleted!');
      fetchAllCitizenships();
    } catch (error) {
      console.error('Error deleting citizenship:', error);
      alert('Error deleting citizenship');
    }
  };

  const handleAddNew = () => {
    setSelectedMember('');
    setEditingId(null);
    setCitizenshipData(null);
    resetForm();
    setViewMode('form');
  };

  const filteredCitizenships = allCitizenships.filter(c => 
    c && (
      (c.full_name || '').toLowerCase().includes((filter || '').toLowerCase()) ||
      (c.citizenship_number || '').toLowerCase().includes((filter || '').toLowerCase()) ||
      getMemberName(c.member_id).toLowerCase().includes((filter || '').toLowerCase())
    )
  );

  const provinces = [
    'Province No. 1',
    'Madhesh Province',
    'Bagmati Province',
    'Gandaki Province',
    'Lumbini Province',
    'Karnali Province',
    'Sudurpashchim Province'
  ];

  return (
    <div className="citizenship-page">
      <header className="page-header">
        <h1>Citizenship Management</h1>
        <p>Manage member citizenship documents and details</p>
      </header>

      {/* All Citizenship Documents Table */}
      {viewMode === 'table' && (
        <div className="form-section">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
            <h2><span className="section-icon">📋</span> Added Citizenship Documents</h2>
            <button className="btn-primary" onClick={handleAddNew}>
              + Add New Citizenship
            </button>
          </div>
          
          <div className="filter-bar">
            <input 
              type="text" 
              placeholder="Search by name, citizenship number..." 
              value={filter} 
              onChange={(e) => setFilter(e.target.value)} 
            />
          </div>

          <div className="table-container">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Member No.</th>
                  <th>Full Name</th>
                  <th>Citizenship No.</th>
                  <th>District</th>
                  <th>Phone</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredCitizenships.length === 0 ? (
                  <tr>
                    <td colSpan="6" style={{ textAlign: 'center', padding: '40px', color: '#888' }}>
                      No citizenship documents added yet.
                    </td>
                  </tr>
                ) : (
                  filteredCitizenships.map(doc => (
                    <tr key={doc.id}>
                      <td>{getMemberNumber(doc.member_id)}</td>
                      <td>{doc.full_name}</td>
                      <td>{doc.citizenship_number}</td>
                      <td>{doc.issued_district || '-'}</td>
                      <td>{doc.phone || '-'}</td>
                      <td>
                        <button className="btn-sm" onClick={() => handleViewFromTable(doc)}>View</button>
                        <button className="btn-sm" onClick={() => handleEditFromTable(doc)}>Edit</button>
                        <button className="btn-sm btn-danger" onClick={() => handleDeleteFromTable(doc.id)}>Delete</button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Back to Table Button */}
      {viewMode === 'form' && (
        <div className="form-section">
          <button className="btn-secondary" onClick={() => setViewMode('table')} style={{ marginBottom: '16px' }}>
            ← Back to List
          </button>
        </div>
      )}

      {/* Add/Edit Form */}
      {viewMode === 'form' && (
        <>
          {/* Member Selection */}
          <div className="form-section member-select-section">
            <h2>Select Member</h2>
            <div className="form-row">
              <select 
                value={selectedMember} 
                onChange={(e) => {
                  setSelectedMember(e.target.value);
                  resetForm();
                }}
                className="member-select"
                required
              >
                <option value="">Select a member</option>
                {members.map(m => (
                  <option key={m.id} value={m.id}>
                    {m.member_number} - {m.member_name}
                  </option>
                ))}
              </select>
            </div>
          </div>

          {selectedMember && (
            <form onSubmit={handleSubmit}>
              {/* Basic Information Section */}
              <div className="form-section">
                <h2><span className="section-icon">📋</span> Basic Information</h2>
                <div className="form-row">
                  <div className="form-group">
                    <label>Full Name *</label>
                    <input 
                      type="text" 
                      placeholder="Enter full name" 
                      value={formData.full_name} 
                      onChange={(e) => setFormData({...formData, full_name: e.target.value})} 
                      required 
                    />
                  </div>
                  <div className="form-group">
                    <label>Citizenship Number *</label>
                    <input 
                      type="text" 
                      placeholder="Enter citizenship number" 
                      value={formData.citizenship_number} 
                      onChange={(e) => setFormData({...formData, citizenship_number: e.target.value})} 
                      required 
                    />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Date of Birth (AD) *</label>
                    <input 
                      type="date" 
                      value={formData.birth_date} 
                      onChange={(e) => setFormData({...formData, birth_date: e.target.value})} 
                      required 
                    />
                  </div>
                  <div className="form-group">
                    <label>Date of Birth (BS) *</label>
                    <input 
                      type="text" 
                      placeholder="e.g., 2080-05-15" 
                      value={formData.birth_date_bs} 
                      onChange={(e) => setFormData({...formData, birth_date_bs: e.target.value})} 
                      required 
                    />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Nationality *</label>
                    <input 
                      type="text" 
                      placeholder="Enter nationality" 
                      value={formData.nationality} 
                      onChange={(e) => setFormData({...formData, nationality: e.target.value})} 
                      required 
                    />
                  </div>
                  <div className="form-group">
                    <label>Marital Status *</label>
                    <select 
                      value={formData.marital_status} 
                      onChange={(e) => setFormData({...formData, marital_status: e.target.value})}
                      required
                    >
                      <option value="">Select status</option>
                      <option value="Single">Single</option>
                      <option value="Married">Married</option>
                      <option value="Divorced">Divorced</option>
                      <option value="Widowed">Widowed</option>
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Spouse Name</label>
                    <input 
                      type="text" 
                      placeholder="Enter spouse name" 
                      value={formData.spouse_name} 
                      onChange={(e) => setFormData({...formData, spouse_name: e.target.value})} 
                    />
                  </div>
                </div>
              </div>

              {/* Citizenship Issue Section */}
              <div className="form-section">
                <h2><span className="section-icon">🪪</span> Citizenship Issue Details</h2>
                <div className="form-row">
                  <div className="form-group">
                    <label>Issue Date (BS) *</label>
                    <input 
                      type="text" 
                      placeholder="e.g., 2080-05-20" 
                      value={formData.issued_date} 
                      onChange={(e) => setFormData({...formData, issued_date: e.target.value})} 
                      required 
                    />
                  </div>
                  <div className="form-group">
                    <label>Issue District *</label>
                    <input 
                      type="text" 
                      placeholder="Enter issue district" 
                      value={formData.issued_district} 
                      onChange={(e) => setFormData({...formData, issued_district: e.target.value})} 
                      required 
                    />
                  </div>
                </div>
              </div>

              {/* Address Section */}
              <div className="form-section">
                <h2><span className="section-icon">📍</span> Address</h2>
                <div className="form-row">
                  <div className="form-group">
                    <label>Province *</label>
                    <select 
                      value={formData.province} 
                      onChange={(e) => setFormData({...formData, province: e.target.value})}
                      required
                    >
                      <option value="">Select province</option>
                      {provinces.map(p => (
                        <option key={p} value={p}>{p}</option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>District *</label>
                    <input 
                      type="text" 
                      placeholder="Enter district" 
                      value={formData.district} 
                      onChange={(e) => setFormData({...formData, district: e.target.value})} 
                      required 
                    />
                  </div>
                  <div className="form-group">
                    <label>Municipality *</label>
                    <input 
                      type="text" 
                      placeholder="Enter municipality/rural municipality" 
                      value={formData.municipality} 
                      onChange={(e) => setFormData({...formData, municipality: e.target.value})} 
                      required 
                    />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Ward Number *</label>
                    <input 
                      type="number" 
                      placeholder="Enter ward number" 
                      value={formData.ward_number} 
                      onChange={(e) => setFormData({...formData, ward_number: e.target.value})} 
                      required 
                    />
                  </div>
                  <div className="form-group">
                    <label>Tole</label>
                    <input 
                      type="text" 
                      placeholder="Enter tole name" 
                      value={formData.tole} 
                      onChange={(e) => setFormData({...formData, tole: e.target.value})} 
                    />
                  </div>
                </div>
              </div>

              {/* Contact Section */}
              <div className="form-section">
                <h2><span className="section-icon">📞</span> Contact Information</h2>
                <div className="form-row">
                  <div className="form-group">
                    <label>Phone Number *</label>
                    <input 
                      type="tel" 
                      placeholder="Enter phone number" 
                      value={formData.phone} 
                      onChange={(e) => setFormData({...formData, phone: e.target.value})} 
                      required 
                    />
                  </div>
                  <div className="form-group">
                    <label>Email Address</label>
                    <input 
                      type="email" 
                      placeholder="Enter email address" 
                      value={formData.email} 
                      onChange={(e) => setFormData({...formData, email: e.target.value})} 
                    />
                  </div>
                </div>
              </div>

              {/* Document Photos Section */}
              <div className="form-section">
                <h2><span className="section-icon">📷</span> Document Photos</h2>
                <div className="photo-upload-section">
                  <div className="photo-upload-item">
                    <label>Profile Photo</label>
                    <input type="file" accept="image/*" onChange={(e) => handleFileChange(e, 'photo')} />
                    {(existingPhotos.photo || photos.photo) && (
                      <div className="photo-preview">
                        {existingPhotos.photo ? 
                          <img src={existingPhotos.photo} alt="Profile" /> : 
                          photos.photo && <img src={URL.createObjectURL(photos.photo)} alt="Profile Preview" />
                        }
                      </div>
                    )}
                  </div>
                  <div className="photo-upload-item">
                    <label>Citizenship Front</label>
                    <input type="file" accept="image/*" onChange={(e) => handleFileChange(e, 'citizenship_front')} />
                    {(existingPhotos.citizenship_front || photos.citizenship_front) && (
                      <div className="photo-preview">
                        {existingPhotos.citizenship_front ? 
                          <img src={existingPhotos.citizenship_front} alt="Citizenship Front" /> : 
                          photos.citizenship_front && <img src={URL.createObjectURL(photos.citizenship_front)} alt="Front Preview" />
                        }
                      </div>
                    )}
                  </div>
                  <div className="photo-upload-item">
                    <label>Citizenship Back</label>
                    <input type="file" accept="image/*" onChange={(e) => handleFileChange(e, 'citizenship_back')} />
                    {(existingPhotos.citizenship_back || photos.citizenship_back) && (
                      <div className="photo-preview">
                        {existingPhotos.citizenship_back ? 
                          <img src={existingPhotos.citizenship_back} alt="Citizenship Back" /> : 
                          photos.citizenship_back && <img src={URL.createObjectURL(photos.citizenship_back)} alt="Back Preview" />
                        }
                      </div>
                    )}
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="form-actions">
                <button type="submit" className="btn-primary" disabled={loading}>
                  {loading ? 'Saving...' : (editingId ? 'Update Details' : 'Save Details')}
                </button>
                {editingId && (
                  <button type="button" className="btn-danger" onClick={handleDelete}>
                    Delete
                  </button>
                )}
              </div>
            </form>
          )}
        </>
      )}

      {/* Saved Documents Preview */}
      {citizenshipData && (
        <div className="citizenship-preview-section">
          <h3>Saved Documents</h3>
          <div className="documents-grid">
            {existingPhotos.photo && (
              <div className="document-card" onClick={viewPhoto}>
                <div className="document-icon">📷</div>
                <span>Profile Photo</span>
              </div>
            )}
            {existingPhotos.citizenship_front && (
              <div className="document-card" onClick={viewPhoto}>
                <div className="document-icon">🪪</div>
                <span>Citizenship Front</span>
              </div>
            )}
            {existingPhotos.citizenship_back && (
              <div className="document-card" onClick={viewPhoto}>
                <div className="document-icon">🪪</div>
                <span>Citizenship Back</span>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Photo Modal */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={() => setShowModal(false)}>×</button>
            <img src={existingPhotos.photo || existingPhotos.citizenship_front || existingPhotos.citizenship_back} alt="Document" />
          </div>
        </div>
      )}

      {/* View Details Modal */}
      {showDetailsModal && selectedDocument && (
        <div className="modal-overlay" onClick={() => setShowDetailsModal(false)}>
          <div className="modal-content modal-large" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={() => setShowDetailsModal(false)}>×</button>
            <h2>Citizenship Details</h2>
            <div className="details-grid">
              <div className="detail-item">
                <label>Member Number</label>
                <span>{getMemberNumber(selectedDocument.member_id)}</span>
              </div>
              <div className="detail-item">
                <label>Full Name</label>
                <span>{selectedDocument.full_name}</span>
              </div>
              <div className="detail-item">
                <label>Citizenship Number</label>
                <span>{selectedDocument.citizenship_number}</span>
              </div>
              <div className="detail-item">
                <label>Date of Birth (BS)</label>
                <span>{selectedDocument.birth_date_bs || '-'}</span>
              </div>
              <div className="detail-item">
                <label>Nationality</label>
                <span>{selectedDocument.nationality || '-'}</span>
              </div>
              <div className="detail-item">
                <label>Marital Status</label>
                <span>{selectedDocument.marital_status || '-'}</span>
              </div>
              <div className="detail-item">
                <label>Issue District</label>
                <span>{selectedDocument.issued_district || '-'}</span>
              </div>
              <div className="detail-item">
                <label>Province</label>
                <span>{selectedDocument.province || '-'}</span>
              </div>
              <div className="detail-item">
                <label>District</label>
                <span>{selectedDocument.district || '-'}</span>
              </div>
              <div className="detail-item">
                <label>Municipality</label>
                <span>{selectedDocument.municipality || '-'}</span>
              </div>
              <div className="detail-item">
                <label>Ward Number</label>
                <span>{selectedDocument.ward_number || '-'}</span>
              </div>
              <div className="detail-item">
                <label>Phone</label>
                <span>{selectedDocument.phone || '-'}</span>
              </div>
            </div>
            <div className="modal-actions">
              <button className="btn-primary" onClick={() => {
                setShowDetailsModal(false);
                handleEditFromTable(selectedDocument);
              }}>Edit</button>
              <button className="btn-danger" onClick={() => {
                setShowDetailsModal(false);
                handleDeleteFromTable(selectedDocument.id);
              }}>Delete</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Profile Page
function ProfilePage() {
  const { user } = useAuth();
  const [name, setName] = useState(user?.name || '');
  const [editing, setEditing] = useState(false);
  const [photo, setPhoto] = useState(null);
  const [preview, setPreview] = useState(null);

  useEffect(() => {
    if (user?.photo) {
      setPreview(user.photo);
    }
  }, [user]);

  const handlePhotoChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setPhoto(file);
      setPreview(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    formData.append('name', name);
    if (photo) formData.append('photo', photo);

    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_BASE}/auth/profile`, {
        method: 'PUT',
        headers: { 'Authorization': `Bearer ${token}` },
        body: formData
      });
      const data = await res.json();
      if (data.success) {
        alert('Profile updated!');
        const updatedUser = { ...user, name, photo: data.user?.photo };
        localStorage.setItem('user', JSON.stringify(updatedUser));
        setEditing(false);
      }
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleDeletePhoto = async () => {
    try {
      const token = localStorage.getItem('token');
      await fetch(`${API_BASE}/auth/profile/photo`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const updatedUser = { ...user, photo: null };
      localStorage.setItem('user', JSON.stringify(updatedUser));
      setPreview(null);
      setPhoto(null);
      alert('Photo deleted!');
    } catch (error) {
      console.error('Error:', error);
    }
  };

  return (
    <div className="profile-page">
      <div className="page-header">
        <h1>My Profile</h1>
        <p>Manage your account settings</p>
      </div>
      <div className="profile-card">
        <div className="profile-header">
          <div className="profile-avatar-section">
            <div className="avatar">
              {preview ? <img src={preview} alt="Profile" style={{ width: '100%', height: '100%', borderRadius: '50%', objectFit: 'cover' }} /> : (user?.name?.[0] || 'U')}
            </div>
            <label className="avatar-upload">
              📷
              <input type="file" accept="image/*" onChange={handlePhotoChange} />
            </label>
          </div>
          <div className="profile-info">
            <h2>{user?.name || 'User'}</h2>
            <p>@{user?.username}</p>
            <span className="status-badge active">{user?.role}</span>
            {editing && (
              <div className="profile-name-input">
                <input type="text" value={name} onChange={e => setName(e.target.value)} placeholder="Enter your name" />
              </div>
            )}
            {editing ? (
              <button className="name-edit-btn" onClick={() => setEditing(false)}>Cancel</button>
            ) : (
              <button className="name-edit-btn" onClick={() => { setEditing(true); setName(user?.name || ''); }}>Edit Name</button>
            )}
          </div>
        </div>
        <div className="profile-details">
          <div className="detail-row">
            <span className="label">Username</span>
            <span className="value">{user?.username}</span>
          </div>
          <div className="detail-row">
            <span className="label">Role</span>
            <span className="value">{user?.role}</span>
          </div>
          {preview && (
            <div className="detail-row">
              <span className="label">Actions</span>
              <span className="value">
                <button className="btn-danger btn-sm" onClick={handleDeletePhoto}>Delete Photo</button>
              </span>
            </div>
          )}
        </div>
        {(editing || photo) && (
          <form onSubmit={handleSubmit}>
            <button type="submit" className="btn-primary" style={{ width: '100%', marginTop: '20px' }}>Save Changes</button>
          </form>
        )}
      </div>
    </div>
  );
}

// Protected Route
function ProtectedRoute({ children }) {
  const { isAuthenticated } = useAuth();
  return isAuthenticated ? children : <Navigate to="/login" />;
}

// Navigation
function Navigation() {
  const { logout } = useAuth();
  return (
    <nav className="sidebar">
      <div className="sidebar-header">
        <div className="logo">
          <svg viewBox="0 0 100 100" className="logo-svg">
            <circle cx="50" cy="50" r="45" fill="#1a365d" stroke="#2c5282" strokeWidth="2"/>
            <path d="M50 20 L50 80 M30 40 L50 20 L70 40" stroke="#fff" strokeWidth="4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
            <circle cx="50" cy="55" r="15" stroke="#2c5282" strokeWidth="2" fill="none"/>
          </svg>
        </div>
      </div>
      <div className="sidebar-nav">
        <Link to="/" className="nav-item"><span className="nav-icon">📊</span> Dashboard</Link>
        <Link to="/members" className="nav-item"><span className="nav-icon">👥</span> Members</Link>
        <Link to="/loans" className="nav-item"><span className="nav-icon">💰</span> Loans</Link>
        <Link to="/shares" className="nav-item"><span className="nav-icon">📊</span> Shares</Link>
        <Link to="/savings" className="nav-item"><span className="nav-icon">🏦</span> Savings</Link>
        <Link to="/monthly-savings" className="nav-item"><span className="nav-icon">📅</span> Monthly Savings</Link>
        <Link to="/citizenship" className="nav-item"><span className="nav-icon">🪪</span> Citizenship</Link>
        <Link to="/profile" className="nav-item"><span className="nav-icon">👤</span> Profile</Link>
      </div>
      <div className="sidebar-footer">
        <button onClick={logout} className="logout-btn">Logout</button>
      </div>
    </nav>
  );
}

// Main App
function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const savedUser = localStorage.getItem('user');
    if (token && savedUser) {
      setIsAuthenticated(true);
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const login = (token, userData) => {
    localStorage.setItem('token', token);
    localStorage.setItem('user', JSON.stringify(userData));
    setIsAuthenticated(true);
    setUser(userData);
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setIsAuthenticated(false);
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ isAuthenticated, user, login, logout }}>
      <Router>
        <div className="app">
          {isAuthenticated && <Navigation />}
          <main className="main-content">
            <Routes>
              <Route path="/login" element={<LoginPage />} />
              <Route path="/" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
              <Route path="/members" element={<ProtectedRoute><MembersPage /></ProtectedRoute>} />
              <Route path="/loans" element={<ProtectedRoute><LoanPage /></ProtectedRoute>} />
              <Route path="/shares" element={<ProtectedRoute><SharePage /></ProtectedRoute>} />
              <Route path="/savings" element={<ProtectedRoute><SavingsPage /></ProtectedRoute>} />
              <Route path="/monthly-savings" element={<ProtectedRoute><MonthlySavingsPage /></ProtectedRoute>} />
              <Route path="/citizenship" element={<ProtectedRoute><CitizenshipPage /></ProtectedRoute>} />
              <Route path="/profile" element={<ProtectedRoute><ProfilePage /></ProtectedRoute>} />
            </Routes>
          </main>
        </div>
      </Router>
    </AuthContext.Provider>
  );
}

export default App;
